  vocab: [{ fr: "Train", ru: "поезд", ipa: "/tʁɛ̃/" }, { fr: "Gare", ru: "вокзал", ipa: "/ɡaʁ/" }, { fr: "Quai", ru: "платформа", ipa: "/kɛ/" }, { fr: "Voie", ru: "путь", ipa: "/vwa/" }, { fr: "Billet aller simple", ru: "билет в одну сторону", ipa: "/bi.jɛ a.le sɛ̃pl/" }, { fr: "Aller-retour", ru: "туда и обратно", ipa: "/a.le ʁə.tuʁ/" }, { fr: "Retard", ru: "задержка", ipa: "/ʁə.taʁ/" }, { fr: "Départ", ru: "отправление", ipa: "/de.paʁ/" }, { fr: "Arrivée", ru: "прибытие", ipa: "/a.ʁi.ve/" }, { fr: "Contrôleur", ru: "контролер", ipa: "/kɔ̃.tʁo.lœʁ/" }],
  phrases: [{ fr: "Un billet pour Lyon, s’il vous plaît.", ru: "Билет до Лиона, пожалуйста.", ipa: "/œ̃ bi.jɛ puʁ ljɔ̃ sil vu plɛ/" }, { fr: "Aller simple ou aller-retour ?", ru: "В одну сторону или туда-обратно?", ipa: "/a.le sɛ̃pl u a.le ʁə.tuʁ/" }, { fr: "De quelle voie part le train ?", ru: "С какого пути отправляется поезд?", ipa: "/də kɛl vwa paʁ lə tʁɛ̃/" }, { fr: "Le train est en retard.", ru: "Поезд задерживается.", ipa: "/lə tʁɛ̃ ɛ zɑ̃ ʁə.taʁ/" }, { fr: "Je cherche le quai trois.", ru: "Я ищу третью платформу.", ipa: "/ʒə ʃɛʁʃ lə kɛ tʁwa/" }, { fr: "Voici mon billet.", ru: "Вот мой билет.", ipa: "/vwa.si mɔ̃ bi.jɛ/" }],
  grammar: "Pour Lyon означает «до Лиона» или «в Лион» при покупке билета. De quelle voie...? — полезный вопрос о пути отправления. Во Франции на вокзалах часто говорят voie для железнодорожного пути.",
  practice: ["Купите билет до Лиона.", "Выберите билет в одну сторону.", "Спросите, с какого пути отправляется поезд.", "Скажите, что поезд задерживается.", "Покажите билет контролеру."]
